#!/usr/bin/env node
// sync-pedagogy.mjs
//
// Syncs the canonical Alexander pedagogy core from the alexander repo
// into this repo as a generated TypeScript module that guide-prompt.ts
// can import.
//
// Canonical source: /Users/tomcassidy/alexander/pedagogy-core/pedagogy-core.md
// Generated target: src/lib/pedagogy-core.generated.ts
//
// The generated file is COMMITTED to this repo so Vercel deploys don't
// need access to the alexander repo at build time. Run this script when
// the canonical source has evolved, then commit the regenerated file.
//
// Usage:
//   npm run sync-pedagogy
//   ALEXANDER_PATH=/path/to/alexander npm run sync-pedagogy

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, '..');

// Resolve alexander repo location. Default to sibling directory; allow
// override via ALEXANDER_PATH env var for non-standard setups.
const ALEXANDER_PATH = process.env.ALEXANDER_PATH
  || join(REPO_ROOT, '..', 'alexander');

const SOURCE = join(ALEXANDER_PATH, 'pedagogy-core', 'pedagogy-core.md');
const TARGET = join(REPO_ROOT, 'src', 'lib', 'pedagogy-core.generated.ts');

if (!existsSync(SOURCE)) {
  console.error(`❌ Canonical pedagogy-core not found at:`);
  console.error(`   ${SOURCE}`);
  console.error(``);
  console.error(`Either:`);
  console.error(`  - Clone the alexander repo to a sibling directory`);
  console.error(`    (expected: ${ALEXANDER_PATH})`);
  console.error(`  - Set ALEXANDER_PATH=/path/to/alexander and re-run`);
  console.error(``);
  console.error(`Source of truth: github.com/thomascassidyzm/alexander`);
  console.error(`                 pedagogy-core/pedagogy-core.md`);
  process.exit(1);
}

const markdown = readFileSync(SOURCE, 'utf8');
const timestamp = new Date().toISOString();

// Escape backticks and ${ so the markdown can live in a TypeScript
// template literal without interpretation.
const escaped = markdown
  .replace(/\\/g, '\\\\')
  .replace(/`/g, '\\`')
  .replace(/\$\{/g, '\\${');

const generated = `// AUTO-GENERATED — do not edit this file directly.
//
// Source: alexander repo, pedagogy-core/pedagogy-core.md
// Synced: ${timestamp}
//
// To re-sync from the canonical source in the alexander repo:
//   npm run sync-pedagogy
//
// To edit the pedagogy core: edit pedagogy-core/pedagogy-core.md in
// the alexander repo (github.com/thomascassidyzm/alexander), push on
// a claude/* branch (auto-merges to main via GH Action), then run
// npm run sync-pedagogy here and commit the regenerated file.

export const PEDAGOGY_CORE = \`${escaped}\`;
`;

writeFileSync(TARGET, generated, 'utf8');

console.log(`✅ Synced pedagogy core`);
console.log(`   source: ${SOURCE}`);
console.log(`   target: ${TARGET}`);
console.log(`   size:   ${markdown.length} chars markdown → ${generated.length} chars TS`);
console.log(``);
console.log(`Next: commit src/lib/pedagogy-core.generated.ts and push.`);
